-- Create a distributed table (run on coordinator)
CREATE TABLE events (
  tenant_id   BIGINT,
  event_id    UUID DEFAULT gen_random_uuid(),
  event_time  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  event_type  TEXT,
  payload     JSONB
);

-- Distribute by tenant_id (queries filtering by tenant_id hit 1 shard group)
SELECT create_distributed_table('events', 'tenant_id');

-- Create a co-located table (same distribution column = join stays local to a shard)
CREATE TABLE metrics (
  tenant_id   BIGINT,
  metric_time TIMESTAMPTZ NOT NULL,
  cpu_pct     NUMERIC,
  mem_pct     NUMERIC
);
SELECT create_distributed_table('metrics', 'tenant_id', colocate_with => 'events');

-- Reference table: replicated to all workers (good for lookup/dimension tables)
CREATE TABLE event_types (
  code TEXT PRIMARY KEY,
  description TEXT
);
SELECT create_reference_table('event_types');

-- Check shard distribution
SELECT shardid, nodename, nodeport, shardminvalue, shardmaxvalue
FROM citus_shards
ORDER BY shardid
LIMIT 10;

-- Show distribution column for each distributed table
SELECT logicalrelid::text AS table_name, column_to_column_name(logicalrelid, partcolumn)
FROM pg_dist_partition;
